#define STR_SIZE 256

#define MAX_PD	(3.0e6)

#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100

#define FACTOR_CHIP	0.5

float t_chip = 0.0005;
float chip_height = 0.016;
float chip_width = 0.016;

float amb_temp = 80.0;

#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

kernel void hotspot(int iteration,  
                    read_only image2d_t power_img,   
                    read_only image2d_t temp_src_img,    
                    write_only image2d_t temp_dst_img,    
                    int grid_cols,  
                    int grid_rows,  
                    int border_cols,  
                    int border_rows,  
                    float Cap,      
                    float Rx, 
                    float Ry, 
                    float Rz, 
                    float step) {

    float step_div_Cap;
    float Rx_1, Ry_1, Rz_1;

    int bx = get_group_id(0);
    int by = get_group_id(1);

    int tx = get_local_id(0);
    int ty = get_local_id(1);

    step_div_Cap = step / Cap;

    Rx_1 = 1.0f / Rx;
    Ry_1 = 1.0f / Ry;
    Rz_1 = 1.0f / Rz;

    int small_block_rows = BLOCK_SIZE - iteration * 2;
    int small_block_cols = BLOCK_SIZE - iteration * 2;

    int blkY = small_block_rows * by - border_rows;
    int blkX = small_block_cols * bx - border_cols;
    int blkYmax = blkY + BLOCK_SIZE - 1;
    int blkXmax = blkX + BLOCK_SIZE - 1;

    int yidx = blkY + ty;
    int xidx = blkX + tx;

    int loadYidx = yidx;
    int loadXidx = xidx;

    float temp_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
    float power_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
    float temp_t[BLOCK_SIZE][BLOCK_SIZE];

    float local_temp = 0.0f;
    float local_power = 0.0f;

    if (IN_RANGE(loadYidx, 0, grid_rows - 1) && IN_RANGE(loadXidx, 0, grid_cols - 1)) {
        local_temp = read_imagef(temp_src_img, CLK_NORMALIZED_COORDS_FALSE, (int2){loadXidx, loadYidx}).x;
        local_power = read_imagef(power_img, CLK_NORMALIZED_COORDS_FALSE, (int2){loadXidx, loadYidx}).x;
    }

    temp_on_cuda[ty][tx] = local_temp;
    power_on_cuda[ty][tx] = local_power;

    barrier(CLK_LOCAL_MEM_FENCE);

    int validYmin = (blkY < 0) ? -blkY : 0;
    int validYmax = (blkYmax > grid_rows - 1) ? BLOCK_SIZE - 1 - (blkYmax - grid_rows + 1) : BLOCK_SIZE - 1;
    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > grid_cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - grid_cols + 1) : BLOCK_SIZE - 1;

    int N = ty - 1;
    int S = ty + 1;
    int W = tx - 1;
    int E = tx + 1;

    N = (N < validYmin) ? validYmin : N;
    S = (S > validYmax) ? validYmax : S;
    W = (W < validXmin) ? validXmin : W;
    E = (E > validXmax) ? validXmax : E;

    bool computed = false;

    for (int i = 0; i < iteration; i++) { 
        computed = false;
        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) &&  
            IN_RANGE(ty, i + 1, BLOCK_SIZE - i - 2) &&  
            IN_RANGE(tx, validXmin, validXmax) && 
            IN_RANGE(ty, validYmin, validYmax)) {

            computed = true;
            float current_temp = temp_on_cuda[ty][tx];
            float north_temp = temp_on_cuda[N][tx];
            float south_temp = temp_on_cuda[S][tx];
            float west_temp = temp_on_cuda[ty][W];
            float east_temp = temp_on_cuda[ty][E];
            float power_val = power_on_cuda[ty][tx];

            temp_t[ty][tx] = current_temp + step_div_Cap * (power_val + 
                (south_temp + north_temp - 2.0f * current_temp) * Ry_1 + 
                (east_temp + west_temp - 2.0f * current_temp) * Rx_1 + 
                (amb_temp - current_temp) * Rz_1);
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        if (i == iteration - 1)
            break;

        if (computed)	
            temp_on_cuda[ty][tx] = temp_t[ty][tx];

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (computed) {
        write_imagef(temp_dst_img, (int2){xidx, yidx}, temp_t[ty][tx]);
    }
}
